good-example.code-block:
-- V10__expand_order_status.sql ALTER TABLE orders ADD COLUMN status_v2 VARCHAR(40);
-- V11__migrate_order_status.sql UPDATE orders SET status_v2 = CASE status WHEN 'P' THEN 'PENDING' WHEN 'S' THEN 'SHIPPED' ELSE 'UNKNOWN' END WHERE status_v2 IS NULL;
-- Application release: write both status and status_v2; read status_v2 with fallback.
-- V12__contract_order_status.sql ALTER TABLE orders ALTER COLUMN status_v2 SET NOT NULL; ALTER TABLE orders DROP COLUMN status;

bad-example.code-block:
-- Bad: changes enum/status meaning in one step with no compatibility window
UPDATE orders SET status = 'PENDING' WHERE status = 'P';
ALTER TABLE orders ALTER COLUMN status SET NOT NULL;
